# Catch-all default server (must be first listening on port 80)
server {
    listen 80 default_server;
    listen [::]:80 default_server;
    server_name _;
    return 444;  # Close connection without response
}

# Wildcard subdomain
server {
    listen 80;
    server_name *.example.com;
    root /var/www/example.com/subdomains;
}

# Multi-domain server block
server {
    listen 80;
    server_name site1.com www.site1.com site2.org;
    root /var/www/multi;
}

server {
    root /var/www/html;

    # Exact match — highest priority
    location = / {
        index index.html;
    }

    # Preferential prefix — skip regex
    location ^~ /static/ {
        expires 365d;
        add_header Cache-Control "public, immutable";
    }

    # Case-insensitive regex for image files
    location ~* \.(jpg|jpeg|png|gif|ico|webp)$ {
        expires 30d;
    }

    # PHP processing
    location ~ \.php$ {
        fastcgi_pass unix:/var/run/php/php8.2-fpm.sock;
        fastcgi_index index.php;
        include fastcgi_params;
    }

    # API proxy
    location /api/ {
        proxy_pass http://backend_api;
        proxy_set_header Host $host;
    }

    # Deny hidden files
    location ~ /\. {
        deny all;
        access_log off;
        log_not_found off;
    }

    # Named location for error fallback
    location @error_404 {
        root /var/www/errors;
        try_files /404.html =404;
    }
    error_page 404 @error_404;
}

